  assert.match(sessionPresentationSource, /payloadPreview:\s*\{[\s\S]*?fontFamily: resolveChatRuntimeMobileFontFamily\(\s+surface\.payloadPreview\.fontFamilyByPlatform,\s+platform \?\? "",\s+\)/);
  assert.match(sessionPresentationSource, /const codeBlock = \{[\s\S]*?fontFamily: resolveChatRuntimeMobileFontFamily\(\s+surface\.codeBlock\.fontFamilyByPlatform,\s+platform \?\? "",\s+\)/);
  assert.match(sessionPresentationSource, /resultCharCount:\s*\{[\s\S]*?fontFamily: resolveChatRuntimeMobileFontFamily\(\s+surface\.characterCount\.fontFamilyByPlatform,\s+platform \?\? "",\s+\)/);
  assert.match(screenSource, /toolName:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.toolName,/);
  assert.match(screenSource, /toolPayloadPreview:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.payloadPreview,/);
  assert.match(screenSource, /toolParamsCode:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.paramsCode,/);
  assert.match(screenSource, /toolResultCharCount:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.resultCharCount,/);
  assert.match(screenSource, /toolResultCode:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.resultCode,/);
  assert.match(screenSource, /toolResultErrorText:\s*\{\s+\.\.\.toolExecutionDetailStyleSlots\.resultErrorText,/);
  assert.doesNotMatch(screenSource, /type MobileFontFamilyByPlatform = Readonly<\{/);
  assert.doesNotMatch(screenSource, /const resolveMobileFontFamily = \(fontFamilyByPlatform: MobileFontFamilyByPlatform\) =>/);
  assert.doesNotMatch(screenSource, /Platform\.OS === 'ios' \? 'Menlo' : 'monospace'/);
